 34ÔćĺBridgeServer::BridgeServer(
 35Ôćĺ    std::shared_ptr<TopicSourceInterface> topic_source,
 36Ôćĺ    std::shared_ptr<SubscriptionManagerInterface> subscription_manager, std::shared_ptr<MiddlewareInterface> middleware,
 37Ôćĺ    int port, double session_timeout, double publish_rate)
 38Ôćĺ    : topic_source_(std::move(topic_source)),
 39Ôćĺ      subscription_manager_(std::move(subscription_manager)),
 40Ôćĺ      middleware_(std::move(middleware)),
 41Ôćĺ      port_(port),
 42Ôćĺ      session_timeout_(session_timeout),
 43Ôćĺ      publish_rate_(publish_rate),
 44Ôćĺ      initialized_(false),
 45Ôćĺ      total_messages_published_(0),
 46Ôćĺ      total_bytes_published_(0),
 47Ôćĺ      publish_cycles_(0) {}
 48Ôćĺ
 49ÔćĺBridgeServer::~BridgeServer() {
 50Ôćĺ  // Shut down the middleware before members are destroyed so that
 51Ôćĺ  // disconnect callbacks (which capture `this`) cannot fire into
 52Ôćĺ  // a partially destroyed BridgeServer.
 53Ôćĺ  if (middleware_) {
 54Ôćĺ    middleware_->shutdown();
 55Ôćĺ  }
 56Ôćĺ}
