 58Ôćĺbool BridgeServer::initialize() {
 59Ôćĺ  if (initialized_) {
 60Ôćĺ    spdlog::warn("Bridge server already initialized");
 61Ôćĺ    return true;
 62Ôćĺ  }
 63Ôćĺ
 64Ôćĺ  spdlog::info("Initializing bridge server...");
 65Ôćĺ
 66Ôćĺ  if (publish_rate_ <= 0.0) {
 67Ôćĺ    spdlog::error("Invalid publish_rate: {:.1f} (must be > 0)", publish_rate_);
 68Ôćĺ    return false;
 69Ôćĺ  }
 70Ôćĺ
 71Ôćĺ  if (port_ < 1 || port_ > 65535) {
 72Ôćĺ    spdlog::error("Invalid port: {} (must be 1-65535)", port_);
 73Ôćĺ    return false;
 74Ôćĺ  }
 75Ôćĺ
 76Ôćĺ  message_buffer_ = std::make_shared<MessageBuffer>();
 77Ôćĺ  session_manager_ = std::make_unique<SessionManager>(session_timeout_);
 78Ôćĺ
 79Ôćĺ  spdlog::info("Core components created");
 80Ôćĺ
 81Ôćĺ  // Set the global message callback to feed into message buffer
 82Ôćĺ  subscription_manager_->set_message_callback(
 83Ôćĺ      [this](const std::string& topic_name, std::shared_ptr<std::vector<std::byte>> cdr_data, uint64_t timestamp_ns) {
 84Ôćĺ        {
 85Ôćĺ          std::lock_guard<std::mutex> lock(stats_mutex_);
 86Ôćĺ          topic_receive_counts_[topic_name]++;
 87Ôćĺ        }
 88Ôćĺ        if (message_buffer_) {
 89Ôćĺ          message_buffer_->add_message(topic_name, timestamp_ns, std::move(cdr_data));
 90Ôćĺ        }
 91Ôćĺ      });
 92Ôćĺ
 93Ôćĺ  // Register disconnect callback before middleware init to avoid missing events
 94Ôćĺ  middleware_->set_on_disconnect([this](const std::string& client_id) {
 95Ôćĺ    spdlog::info("Client disconnected: '{}'", client_id);
 96Ôćĺ    cleanup_session(client_id);
 97Ôćĺ  });
 98Ôćĺ
 99Ôćĺ  // Initialize middleware (may start accepting connections immediately)
100Ôćĺ  auto result = middleware_->initialize(static_cast<uint16_t>(port_));
101Ôćĺ  if (!result) {
102Ôćĺ    spdlog::error("Failed to initialize middleware: {}", result.error());
103Ôćĺ    return false;
104Ôćĺ  }
105Ôćĺ  spdlog::info("Middleware initialized (port: {})", port_);
106Ôćĺ
107Ôćĺ  initialized_ = true;
108Ôćĺ  spdlog::info("Bridge server initialization complete");
109Ôćĺ
110Ôćĺ  return true;
111Ôćĺ}
112Ôćĺ
113Ôćĺbool BridgeServer::process_requests() {
114Ôćĺ  if (!initialized_) {
115Ôćĺ    spdlog::error("Bridge server not initialized");
116Ôćĺ    return false;
117Ôćĺ  }
118Ôćĺ
119Ôćĺ  // Receive request (non-blocking with timeout)
120Ôćĺ  std::vector<uint8_t> request_data;
121Ôćĺ  std::string client_id;
122Ôćĺ  bool received = middleware_->receive_request(request_data, client_id);
123Ôćĺ
124Ôćĺ  if (!received || request_data.empty()) {
125Ôćĺ    return false;
126Ôćĺ  }
127Ôćĺ
128Ôćĺ  std::string request(request_data.begin(), request_data.end());
129Ôćĺ  if (client_id.empty()) {
130Ôćĺ    spdlog::warn("Received request with no client identity");
131Ôćĺ    return true;
132Ôćĺ  }
133Ôćĺ
134Ôćĺ  // Parse request JSON
135Ôćĺ  std::string response;
136Ôćĺ  json request_json;
137Ôćĺ  try {
138Ôćĺ    request_json = json::parse(request);
139Ôćĺ
140Ôćĺ    if (!request_json.contains("command")) {
141Ôćĺ      response = create_error_response("INVALID_REQUEST", "Missing 'command' field", request_json);
142Ôćĺ    } else {
143Ôćĺ      std::string command = request_json["command"];
144Ôćĺ
145Ôćĺ      spdlog::debug("Processing '{}' command from client '{}'", command, client_id);
146Ôćĺ
147Ôćĺ      if (command == "get_topics") {
148Ôćĺ        response = handle_get_topics(client_id, request_json);
149Ôćĺ      } else if (command == "subscribe") {
150Ôćĺ        response = handle_subscribe(client_id, request_json);
151Ôćĺ      } else if (command == "unsubscribe") {
152Ôćĺ        response = handle_unsubscribe(client_id, request_json);
153Ôćĺ      } else if (command == "heartbeat") {
154Ôćĺ        response = handle_heartbeat(client_id, request_json);
155Ôćĺ      } else if (command == "pause") {
156Ôćĺ        response = handle_pause(client_id, request_json);
157Ôćĺ      } else if (command == "resume") {
158Ôćĺ        response = handle_resume(client_id, request_json);
159Ôćĺ      } else {
160Ôćĺ        response = create_error_response("UNKNOWN_COMMAND", "Unknown command: " + command, request_json);
161Ôćĺ      }
162Ôćĺ    }
163Ôćĺ  } catch (const json::exception& e) {
164Ôćĺ    spdlog::error("JSON parse error: {}", e.what());
165Ôćĺ    response = create_error_response("INVALID_JSON", "Failed to parse JSON request", json::object());
166Ôćĺ  } catch (const std::exception& e) {
167Ôćĺ    spdlog::error("Error processing request: {}", e.what());
168Ôćĺ    response = create_error_response("INTERNAL_ERROR", "Internal server error", request_json);
169Ôćĺ  }
170Ôćĺ
171Ôćĺ  // Send response to the specific client
172Ôćĺ  std::vector<uint8_t> response_data(response.begin(), response.end());
173Ôćĺ  if (!middleware_->send_reply(client_id, response_data)) {
174Ôćĺ    spdlog::warn("Failed to send response to client '{}', cleaning up session", client_id);
175Ôćĺ    cleanup_session(client_id);
176Ôćĺ  }
177Ôćĺ  return true;
178Ôćĺ}
