180Ôćĺstd::string BridgeServer::handle_get_topics(const std::string& client_id, const nlohmann::json& request) {
181Ôćĺ  if (!session_manager_->session_exists(client_id)) {
182Ôćĺ    session_manager_->create_session(client_id);
183Ôćĺ    spdlog::info("Created new session for client '{}'", client_id);
184Ôćĺ  }
185Ôćĺ
186Ôćĺ  session_manager_->update_heartbeat(client_id);
187Ôćĺ
188Ôćĺ  auto topics = topic_source_->get_topics();
189Ôćĺ
190Ôćĺ  json response;
191Ôćĺ  response["status"] = "success";
192Ôćĺ  response["topics"] = json::array();
193Ôćĺ
194Ôćĺ  for (const auto& topic : topics) {
195Ôćĺ    json topic_entry;
196Ôćĺ    topic_entry["name"] = topic.name;
197Ôćĺ    topic_entry["type"] = topic.type;
198Ôćĺ    response["topics"].push_back(topic_entry);
199Ôćĺ  }
200Ôćĺ
201Ôćĺ  inject_response_fields(response, request);
202Ôćĺ
203Ôćĺ  spdlog::info("Returning {} topics to client '{}'", topics.size(), client_id);
204Ôćĺ
205Ôćĺ  return response.dump();
206Ôćĺ}
