208Ôćĺstd::string BridgeServer::handle_subscribe(const std::string& client_id, const nlohmann::json& request) {
209Ôćĺ  if (!session_manager_->session_exists(client_id)) {
210Ôćĺ    session_manager_->create_session(client_id);
211Ôćĺ    spdlog::info("Created new session for client '{}'", client_id);
212Ôćĺ  }
213Ôćĺ
214Ôćĺ  session_manager_->update_heartbeat(client_id);
215Ôćĺ
216Ôćĺ  if (!request.contains("topics")) {
217Ôćĺ    return create_error_response("INVALID_REQUEST", "Missing 'topics' field", request);
218Ôćĺ  }
219Ôćĺ
220Ôćĺ  if (!request["topics"].is_array()) {
221Ôćĺ    return create_error_response("INVALID_REQUEST", "'topics' must be an array", request);
222Ôćĺ  }
223Ôćĺ
224Ôćĺ  auto current_subs = session_manager_->get_subscriptions(client_id);
225Ôćĺ
226Ôćĺ  // Parse requested topics ÔÇö supports mixed array of strings and objects:
227Ôćĺ  //   ["topic1", {"name": "topic2", "max_rate_hz": 10.0}]
228Ôćĺ  std::unordered_map<std::string, double> requested_topics;
229Ôćĺ  for (const auto& topic : request["topics"]) {
230Ôćĺ    if (topic.is_string()) {
231Ôćĺ      requested_topics[topic.get<std::string>()] = 0.0;
232Ôćĺ    } else if (topic.is_object() && topic.contains("name") && topic["name"].is_string()) {
233Ôćĺ      double rate_hz = 0.0;
234Ôćĺ      if (topic.contains("max_rate_hz") && topic["max_rate_hz"].is_number()) {
235Ôćĺ        rate_hz = topic["max_rate_hz"].get<double>();
236Ôćĺ        if (rate_hz < 0.0) {
237Ôćĺ          rate_hz = 0.0;
238Ôćĺ        }
239Ôćĺ      }
240Ôćĺ      requested_topics[topic["name"].get<std::string>()] = rate_hz;
241Ôćĺ    }
242Ôćĺ  }
243Ôćĺ
244Ôćĺ  // Determine which topics to add (additive model ÔÇö subscribe only adds, never removes)
245Ôćĺ  std::vector<std::string> topics_to_add;
246Ôćĺ  for (const auto& [topic, rate] : requested_topics) {
247Ôćĺ    if (current_subs.find(topic) == current_subs.end()) {
248Ôćĺ      topics_to_add.push_back(topic);
249Ôćĺ    }
250Ôćĺ  }
251Ôćĺ
252Ôćĺ  // Build topic name Ôćĺ type lookup from topic source
253Ôćĺ  auto available_topics = topic_source_->get_topics();
254Ôćĺ  std::unordered_map<std::string, std::string> topic_types;
255Ôćĺ  for (const auto& topic : available_topics) {
256Ôćĺ    topic_types[topic.name] = topic.type;
257Ôćĺ  }
258Ôćĺ
259Ôćĺ  // Subscribe to new topics ÔÇö track successes and failures
260Ôćĺ  json schemas = json::object();
261Ôćĺ  json failures = json::array();
262Ôćĺ
263Ôćĺ  for (const auto& topic_name : topics_to_add) {
264Ôćĺ    if (topic_types.find(topic_name) == topic_types.end()) {
265Ôćĺ      spdlog::warn("Client '{}' requested non-existent topic '{}'", client_id, topic_name);
266Ôćĺ      json failure;
267Ôćĺ      failure["topic"] = topic_name;
268Ôćĺ      failure["reason"] = "Topic does not exist";
269Ôćĺ      failures.push_back(failure);
270Ôćĺ      continue;
271Ôćĺ    }
272Ôćĺ
273Ôćĺ    std::string topic_type = topic_types[topic_name];
274Ôćĺ
275Ôćĺ    // Get schema BEFORE subscribing to avoid corrupting the reference count
276Ôćĺ    // if schema extraction fails after subscribe() increments it.
277Ôćĺ    std::string schema;
278Ôćĺ    try {
279Ôćĺ      schema = topic_source_->get_schema(topic_name);
280Ôćĺ    } catch (const std::exception& e) {
281Ôćĺ      spdlog::error("Failed to get schema for topic '{}': {}", topic_name, e.what());
282Ôćĺ      json failure;
283Ôćĺ      failure["topic"] = topic_name;
284Ôćĺ      failure["reason"] = std::string("Schema extraction failed: ") + e.what();
285Ôćĺ      failures.push_back(failure);
286Ôćĺ      continue;
287Ôćĺ    }
288Ôćĺ
289Ôćĺ    if (schema.empty()) {
290Ôćĺ      spdlog::error("Empty schema for topic '{}' (type: {})", topic_name, topic_type);
291Ôćĺ      json failure;
292Ôćĺ      failure["topic"] = topic_name;
293Ôćĺ      failure["reason"] = "Schema extraction returned empty definition";
294Ôćĺ      failures.push_back(failure);
295Ôćĺ      continue;
296Ôćĺ    }
297Ôćĺ
298Ôćĺ    // Subscribe via subscription manager (ref-counted)
299Ôćĺ    bool success = subscription_manager_->subscribe(topic_name, topic_type);
300Ôćĺ    if (!success) {
301Ôćĺ      spdlog::error("Failed to subscribe to topic '{}'", topic_name);
302Ôćĺ      json failure;
303Ôćĺ      failure["topic"] = topic_name;
304Ôćĺ      failure["reason"] = "Subscription manager failed to create subscription";
305Ôćĺ      failures.push_back(failure);
306Ôćĺ      continue;
307Ôćĺ    }
308Ôćĺ
309Ôćĺ    // Immediately add to session. If session is gone (client disconnected
310Ôćĺ    // between subscribe and now), roll back the ref count.
311Ôćĺ    if (!session_manager_->add_subscription(client_id, topic_name, requested_topics[topic_name])) {
312Ôćĺ      spdlog::warn("Session gone for client '{}', rolling back subscribe for '{}'", client_id, topic_name);
313Ôćĺ      subscription_manager_->unsubscribe(topic_name);
314Ôćĺ      continue;
315Ôćĺ    }
316Ôćĺ
317Ôćĺ    nlohmann::json schema_obj;
318Ôćĺ    schema_obj["encoding"] = topic_source_->schema_encoding();
319Ôćĺ    schema_obj["definition"] = schema;
320Ôćĺ    schemas[topic_name] = schema_obj;
321Ôćĺ
322Ôćĺ    spdlog::info("Client '{}' subscribed to topic '{}' (type: {})", client_id, topic_name, topic_type);
323Ôćĺ  }
324Ôćĺ
325Ôćĺ  // Update rates for topics that were already subscribed but may have a new rate
326Ôćĺ  for (const auto& [topic, rate] : requested_topics) {
327Ôćĺ    if (current_subs.find(topic) != current_subs.end()) {
328Ôćĺ      session_manager_->add_subscription(client_id, topic, rate);
329Ôćĺ    }
330Ôćĺ  }
331Ôćĺ
332Ôćĺ  // Build response
333Ôćĺ  json response;
334Ôćĺ  if (failures.empty()) {
335Ôćĺ    response["status"] = "success";
336Ôćĺ  } else if (schemas.empty()) {
337Ôćĺ    response["status"] = "error";
338Ôćĺ    response["error_code"] = "ALL_SUBSCRIPTIONS_FAILED";
339Ôćĺ    response["message"] = "Failed to subscribe to all requested topics";
340Ôćĺ  } else {
341Ôćĺ    response["status"] = "partial_success";
342Ôćĺ    response["message"] = "Some subscriptions failed";
343Ôćĺ  }
344Ôćĺ
345Ôćĺ  response["schemas"] = schemas;
346Ôćĺ  if (!failures.empty()) {
347Ôćĺ    response["failures"] = failures;
348Ôćĺ  }
349Ôćĺ
350Ôćĺ  // Include rate limits in response for topics with non-zero rates
351Ôćĺ  json rate_limits = json::object();
352Ôćĺ  auto updated_subs = session_manager_->get_subscriptions(client_id);
353Ôćĺ  for (const auto& [topic, rate] : updated_subs) {
354Ôćĺ    if (rate > 0.0) {
355Ôćĺ      rate_limits[topic] = rate;
356Ôćĺ    }
357Ôćĺ  }
358Ôćĺ  if (!rate_limits.empty()) {
359Ôćĺ    response["rate_limits"] = rate_limits;
360Ôćĺ  }
361Ôćĺ
362Ôćĺ  inject_response_fields(response, request);
363Ôćĺ
364Ôćĺ  return response.dump();
365Ôćĺ}
