367Ôćĺstd::string BridgeServer::handle_unsubscribe(const std::string& client_id, const nlohmann::json& request) {
368Ôćĺ  if (!session_manager_->session_exists(client_id)) {
369Ôćĺ    session_manager_->create_session(client_id);
370Ôćĺ    spdlog::info("Created new session for client '{}'", client_id);
371Ôćĺ  }
372Ôćĺ
373Ôćĺ  session_manager_->update_heartbeat(client_id);
374Ôćĺ
375Ôćĺ  if (!request.contains("topics") || !request["topics"].is_array()) {
376Ôćĺ    return create_error_response("INVALID_REQUEST", "Missing or invalid 'topics' array", request);
377Ôćĺ  }
378Ôćĺ
379Ôćĺ  auto current_subs = session_manager_->get_subscriptions(client_id);
380Ôćĺ
381Ôćĺ  std::vector<std::string> removed;
382Ôćĺ
383Ôćĺ  for (const auto& topic_item : request["topics"]) {
384Ôćĺ    std::string topic_name;
385Ôćĺ    if (topic_item.is_string()) {
386Ôćĺ      topic_name = topic_item.get<std::string>();
387Ôćĺ    } else if (topic_item.is_object() && topic_item.contains("name") && topic_item["name"].is_string()) {
388Ôćĺ      topic_name = topic_item["name"].get<std::string>();
389Ôćĺ    } else {
390Ôćĺ      continue;
391Ôćĺ    }
392Ôćĺ
393Ôćĺ    if (current_subs.find(topic_name) != current_subs.end()) {
394Ôćĺ      subscription_manager_->unsubscribe(topic_name);
395Ôćĺ      current_subs.erase(topic_name);
396Ôćĺ      removed.push_back(topic_name);
397Ôćĺ
398Ôćĺ      spdlog::info("Client '{}' unsubscribed from topic '{}'", client_id, topic_name);
399Ôćĺ    }
400Ôćĺ  }
401Ôćĺ
402Ôćĺ  session_manager_->update_subscriptions(client_id, current_subs);
403Ôćĺ
404Ôćĺ  json response;
405Ôćĺ  response["status"] = "success";
406Ôćĺ  response["removed"] = removed;
407Ôćĺ  inject_response_fields(response, request);
408Ôćĺ
409Ôćĺ  return response.dump();
410Ôćĺ}
