412Ôćĺstd::string BridgeServer::handle_heartbeat(const std::string& client_id, const nlohmann::json& request) {
413Ôćĺ  if (!session_manager_->session_exists(client_id)) {
414Ôćĺ    session_manager_->create_session(client_id);
415Ôćĺ    spdlog::info("Created new session for client '{}'", client_id);
416Ôćĺ  }
417Ôćĺ
418Ôćĺ  session_manager_->update_heartbeat(client_id);
419Ôćĺ
420Ôćĺ  spdlog::debug("Heartbeat received from client '{}'", client_id);
421Ôćĺ
422Ôćĺ  json response;
423Ôćĺ  response["status"] = "ok";
424Ôćĺ  inject_response_fields(response, request);
425Ôćĺ
426Ôćĺ  return response.dump();
427Ôćĺ}
