429Ôćĺstd::string BridgeServer::handle_pause(const std::string& client_id, const nlohmann::json& request) {
430Ôćĺ  if (!session_manager_->session_exists(client_id)) {
431Ôćĺ    session_manager_->create_session(client_id);
432Ôćĺ    spdlog::info("Created new session for client '{}'", client_id);
433Ôćĺ  }
434Ôćĺ
435Ôćĺ  session_manager_->update_heartbeat(client_id);
436Ôćĺ
437Ôćĺ  if (session_manager_->is_paused(client_id)) {
438Ôćĺ    spdlog::debug("Client '{}' already paused", client_id);
439Ôćĺ    json response;
440Ôćĺ    response["status"] = "ok";
441Ôćĺ    response["paused"] = true;
442Ôćĺ    inject_response_fields(response, request);
443Ôćĺ    return response.dump();
444Ôćĺ  }
445Ôćĺ
446Ôćĺ  session_manager_->set_paused(client_id, true);
447Ôćĺ
448Ôćĺ  // Decrement ref counts for all subscribed topics
449Ôćĺ  auto subs = session_manager_->get_subscriptions(client_id);
450Ôćĺ  for (const auto& [topic, rate] : subs) {
451Ôćĺ    subscription_manager_->unsubscribe(topic);
452Ôćĺ    spdlog::debug("Decremented ref count for topic '{}' (client '{}' paused)", topic, client_id);
453Ôćĺ  }
454Ôćĺ
455Ôćĺ  spdlog::info("Client '{}' paused ({} topics refs decremented)", client_id, subs.size());
456Ôćĺ
457Ôćĺ  json response;
458Ôćĺ  response["status"] = "ok";
459Ôćĺ  response["paused"] = true;
460Ôćĺ  inject_response_fields(response, request);
461Ôćĺ  return response.dump();
462Ôćĺ}
