464Ôćĺstd::string BridgeServer::handle_resume(const std::string& client_id, const nlohmann::json& request) {
465Ôćĺ  if (!session_manager_->session_exists(client_id)) {
466Ôćĺ    session_manager_->create_session(client_id);
467Ôćĺ    spdlog::info("Created new session for client '{}'", client_id);
468Ôćĺ  }
469Ôćĺ
470Ôćĺ  session_manager_->update_heartbeat(client_id);
471Ôćĺ
472Ôćĺ  if (!session_manager_->is_paused(client_id)) {
473Ôćĺ    spdlog::debug("Client '{}' not paused", client_id);
474Ôćĺ    json response;
475Ôćĺ    response["status"] = "ok";
476Ôćĺ    response["paused"] = false;
477Ôćĺ    inject_response_fields(response, request);
478Ôćĺ    return response.dump();
479Ôćĺ  }
480Ôćĺ
481Ôćĺ  session_manager_->set_paused(client_id, false);
482Ôćĺ
483Ôćĺ  // Build topic name Ôćĺ type lookup for subscribe calls
484Ôćĺ  auto available_topics = topic_source_->get_topics();
485Ôćĺ  std::unordered_map<std::string, std::string> topic_types;
486Ôćĺ  for (const auto& t : available_topics) {
487Ôćĺ    topic_types[t.name] = t.type;
488Ôćĺ  }
489Ôćĺ
490Ôćĺ  // Increment ref counts for all subscribed topics
491Ôćĺ  auto subs = session_manager_->get_subscriptions(client_id);
492Ôćĺ  std::vector<std::string> failed_topics;
493Ôćĺ  for (const auto& [topic, rate] : subs) {
494Ôćĺ    auto type_it = topic_types.find(topic);
495Ôćĺ    if (type_it == topic_types.end()) {
496Ôćĺ      spdlog::warn("Topic '{}' no longer exists, cannot re-subscribe for client '{}'", topic, client_id);
497Ôćĺ      failed_topics.push_back(topic);
498Ôćĺ      continue;
499Ôćĺ    }
500Ôćĺ    bool ok = subscription_manager_->subscribe(topic, type_it->second);
501Ôćĺ    if (ok) {
502Ôćĺ      spdlog::debug("Incremented ref count for topic '{}' (client '{}' resumed)", topic, client_id);
503Ôćĺ    } else {
504Ôćĺ      spdlog::warn("Topic '{}' subscription failed on resume for client '{}'", topic, client_id);
505Ôćĺ      failed_topics.push_back(topic);
506Ôćĺ    }
507Ôćĺ  }
508Ôćĺ
509Ôćĺ  // Remove failed topics from session to prevent ref-count underflow on disconnect
510Ôćĺ  for (const auto& topic : failed_topics) {
511Ôćĺ    session_manager_->remove_subscription(client_id, topic);
512Ôćĺ  }
513Ôćĺ
514Ôćĺ  spdlog::info(
515Ôćĺ      "Client '{}' resumed ({} topics re-subscribed, {} failed)", client_id, subs.size() - failed_topics.size(),
516Ôćĺ      failed_topics.size());
517Ôćĺ
518Ôćĺ  json response;
519Ôćĺ  response["status"] = "ok";
520Ôćĺ  response["paused"] = false;
521Ôćĺ  inject_response_fields(response, request);
522Ôćĺ  return response.dump();
523Ôćĺ}
