556Ôćĺvoid BridgeServer::cleanup_session(const std::string& client_id) {
557Ôćĺ  std::lock_guard<std::mutex> lock(cleanup_mutex_);
558Ôćĺ
559Ôćĺ  if (!session_manager_->session_exists(client_id)) {
560Ôćĺ    return;
561Ôćĺ  }
562Ôćĺ
563Ôćĺ  auto subscriptions = session_manager_->get_subscriptions(client_id);
564Ôćĺ  bool was_paused = session_manager_->is_paused(client_id);
565Ôćĺ
566Ôćĺ  // Unsubscribe from all topics (only if not paused ÔÇö paused clients already decremented ref counts)
567Ôćĺ  if (!was_paused) {
568Ôćĺ    for (const auto& [topic, rate] : subscriptions) {
569Ôćĺ      subscription_manager_->unsubscribe(topic);
570Ôćĺ      spdlog::debug("Unsubscribed client '{}' from topic '{}'", client_id, topic);
571Ôćĺ    }
572Ôćĺ  }
573Ôćĺ
574Ôćĺ  session_manager_->remove_session(client_id);
575Ôćĺ
576Ôćĺ  {
577Ôćĺ    std::lock_guard<std::mutex> sent_lock(last_sent_mutex_);
578Ôćĺ    last_sent_times_.erase(client_id);
579Ôćĺ  }
580Ôćĺ
581Ôćĺ  spdlog::info("Cleaned up session for client '{}' ({} topics unsubscribed)", client_id, subscriptions.size());
582Ôćĺ}
