607Ôćĺvoid BridgeServer::publish_aggregated_messages() {
608Ôćĺ  if (!initialized_) {
609Ôćĺ    return;
610Ôćĺ  }
611Ôćĺ
612Ôćĺ  std::unordered_map<std::string, std::deque<BufferedMessage>> messages;
613Ôćĺ  message_buffer_->move_messages(messages);
614Ôćĺ
615Ôćĺ  if (messages.empty()) {
616Ôćĺ    return;
617Ôćĺ  }
618Ôćĺ
619Ôćĺ  try {
620Ôćĺ    auto active_sessions = session_manager_->get_active_sessions();
621Ôćĺ    if (active_sessions.empty()) {
622Ôćĺ      return;
623Ôćĺ    }
624Ôćĺ
625Ôćĺ    // Group clients by subscription config (topic + rate) to avoid redundant serialization.
626Ôćĺ    using GroupKey = std::map<std::string, int>;
627Ôćĺ    std::map<GroupKey, std::vector<std::string>> subscription_groups;
628Ôćĺ    std::unordered_map<std::string, std::unordered_map<std::string, double>> client_subs;
629Ôćĺ
630Ôćĺ    for (const auto& client_id : active_sessions) {
631Ôćĺ      auto subs = session_manager_->get_subscriptions(client_id);
632Ôćĺ      if (subs.empty()) {
633Ôćĺ        continue;
634Ôćĺ      }
635Ôćĺ      GroupKey key;
636Ôćĺ      for (const auto& [topic, rate_hz] : subs) {
637Ôćĺ        key[topic] = static_cast<int>(rate_hz * 1000);
638Ôćĺ      }
639Ôćĺ      subscription_groups[key].push_back(client_id);
640Ôćĺ      client_subs[client_id] = std::move(subs);
641Ôćĺ    }
642Ôćĺ
643Ôćĺ    size_t total_msg_count = 0;
644Ôćĺ    size_t total_bytes = 0;
645Ôćĺ    std::unordered_map<std::string, uint64_t> forward_counts;
646Ôćĺ
647Ôćĺ    // Collect paused state outside of last_sent_mutex_ to avoid lock ordering issues.
648Ôćĺ    std::unordered_map<std::string, bool> paused_state;
649Ôćĺ    for (const auto& [group_key, client_ids] : subscription_groups) {
650Ôćĺ      for (const auto& client_id : client_ids) {
651Ôćĺ        paused_state[client_id] = session_manager_->is_paused(client_id);
652Ôćĺ      }
653Ôćĺ    }
654Ôćĺ
655Ôćĺ    // Per-group serialized frames, built under last_sent_mutex_ for rate limiting
656Ôćĺ    struct GroupFrame {
657Ôćĺ      std::vector<uint8_t> compressed_data;
658Ôćĺ      size_t msg_count;
659Ôćĺ      std::vector<std::string> client_ids;
660Ôćĺ    };
661Ôćĺ    std::vector<GroupFrame> frames;
662Ôćĺ
663Ôćĺ    {
664Ôćĺ      std::lock_guard<std::mutex> sent_lock(last_sent_mutex_);
665Ôćĺ
666Ôćĺ      for (const auto& [group_key, client_ids] : subscription_groups) {
667Ôćĺ        AggregatedMessageSerializer serializer;
668Ôćĺ        size_t group_msg_count = 0;
669Ôćĺ
670Ôćĺ        const auto& representative_subs = client_subs[client_ids.front()];
671Ôćĺ        auto& rep_last_sent = last_sent_times_[client_ids.front()];
672Ôćĺ
673Ôćĺ        for (const auto& [topic, msgs] : messages) {
674Ôćĺ          auto sub_it = representative_subs.find(topic);
675Ôćĺ          if (sub_it == representative_subs.end()) {
676Ôćĺ            continue;
677Ôćĺ          }
678Ôćĺ
679Ôćĺ          double rate_hz = sub_it->second;
680Ôćĺ          int rate_mhz = static_cast<int>(rate_hz * 1000);
681Ôćĺ
682Ôćĺ          if (rate_mhz == 0) {
683Ôćĺ            for (const auto& msg : msgs) {
684Ôćĺ              serializer.serialize_message(topic, msg.timestamp_ns, msg.data->data(), msg.data->size());
685Ôćĺ              group_msg_count++;
686Ôćĺ              forward_counts[topic]++;
687Ôćĺ            }
688Ôćĺ          } else {
689Ôćĺ            uint64_t min_interval_ns = static_cast<uint64_t>(1'000'000'000'000) / static_cast<uint64_t>(rate_mhz);
690Ôćĺ            uint64_t last_sent = rep_last_sent[topic];
691Ôćĺ
692Ôćĺ            for (const auto& msg : msgs) {
693Ôćĺ              if (msg.timestamp_ns >= last_sent + min_interval_ns) {
694Ôćĺ                serializer.serialize_message(topic, msg.timestamp_ns, msg.data->data(), msg.data->size());
695Ôćĺ                last_sent = msg.timestamp_ns;
696Ôćĺ                group_msg_count++;
697Ôćĺ                forward_counts[topic]++;
698Ôćĺ              }
699Ôćĺ            }
700Ôćĺ            rep_last_sent[topic] = last_sent;
701Ôćĺ          }
702Ôćĺ        }
703Ôćĺ
704Ôćĺ        if (group_msg_count == 0) {
705Ôćĺ          continue;
706Ôćĺ        }
707Ôćĺ
708Ôćĺ        GroupFrame frame;
709Ôćĺ        frame.compressed_data = serializer.finalize();
710Ôćĺ        frame.msg_count = group_msg_count;
711Ôćĺ        frame.client_ids = client_ids;
712Ôćĺ
713Ôćĺ        // Propagate rate-limiting state to other clients in the group
714Ôćĺ        for (const auto& client_id : client_ids) {
715Ôćĺ          if (client_id != client_ids.front()) {
716Ôćĺ            last_sent_times_[client_id] = rep_last_sent;
717Ôćĺ          }
718Ôćĺ        }
719Ôćĺ
720Ôćĺ        frames.push_back(std::move(frame));
721Ôćĺ      }
722Ôćĺ    }  // last_sent_mutex_ released here
723Ôćĺ
724Ôćĺ    // Send frames outside of any lock
725Ôćĺ    for (const auto& frame : frames) {
726Ôćĺ      bool any_sent = false;
727Ôćĺ      for (const auto& client_id : frame.client_ids) {
728Ôćĺ        auto it = paused_state.find(client_id);
729Ôćĺ        if (it != paused_state.end() && it->second) {
730Ôćĺ          continue;
731Ôćĺ        }
732Ôćĺ        if (middleware_->send_binary(client_id, frame.compressed_data)) {
733Ôćĺ          any_sent = true;
734Ôćĺ        } else {
735Ôćĺ          spdlog::debug("Failed to send binary frame to client '{}'", client_id);
736Ôćĺ        }
737Ôćĺ      }
738Ôćĺ
739Ôćĺ      if (any_sent) {
740Ôćĺ        total_msg_count += frame.msg_count;
741Ôćĺ        total_bytes += frame.compressed_data.size();
742Ôćĺ      }
743Ôćĺ    }
744Ôćĺ
745Ôćĺ    if (total_msg_count > 0) {
746Ôćĺ      std::lock_guard<std::mutex> lock(stats_mutex_);
747Ôćĺ      total_messages_published_ += total_msg_count;
748Ôćĺ      total_bytes_published_ += total_bytes;
749Ôćĺ      publish_cycles_++;
750Ôćĺ      for (const auto& [topic, count] : forward_counts) {
751Ôćĺ        topic_forward_counts_[topic] += count;
752Ôćĺ      }
753Ôćĺ    }
754Ôćĺ  } catch (const std::exception& e) {
755Ôćĺ    spdlog::error("Error publishing aggregated messages: {}", e.what());
756Ôćĺ  }
757Ôćĺ}
