37Ôćĺbool Ros2SubscriptionManager::subscribe(const std::string& topic_name, const std::string& topic_type) {
38Ôćĺ  bool needs_stripping = strip_large_messages_ && MessageStripper::should_strip(topic_type);
39Ôćĺ
40Ôćĺ  Ros2MessageCallback ros2_callback =
41Ôćĺ      [this, topic_type, needs_stripping](
42Ôćĺ          const std::string& topic, const std::shared_ptr<rclcpp::SerializedMessage>& msg, uint64_t receive_time_ns) {
43Ôćĺ        const rclcpp::SerializedMessage* msg_to_use = msg.get();
44Ôćĺ        std::optional<rclcpp::SerializedMessage> stripped_msg;
45Ôćĺ
46Ôćĺ        if (needs_stripping) {
47Ôćĺ          try {
48Ôćĺ            stripped_msg.emplace(MessageStripper::strip(topic_type, *msg));
49Ôćĺ            msg_to_use = &*stripped_msg;
50Ôćĺ          } catch (const std::exception& e) {
51Ôćĺ            spdlog::warn("Failed to strip message on topic '{}': {}. Forwarding original.", topic, e.what());
52Ôćĺ          }
53Ôćĺ        }
54Ôćĺ
55Ôćĺ        const auto& rcl_msg = msg_to_use->get_rcl_serialized_message();
56Ôćĺ        auto data = std::make_shared<std::vector<std::byte>>(rcl_msg.buffer_length);
57Ôćĺ        std::memcpy(data->data(), rcl_msg.buffer, rcl_msg.buffer_length);
58Ôćĺ
59Ôćĺ        MessageCallback cb;
60Ôćĺ        {
61Ôćĺ          std::lock_guard<std::mutex> lock(callback_mutex_);
62Ôćĺ          cb = callback_;
63Ôćĺ        }
64Ôćĺ        if (cb) {
65Ôćĺ          cb(topic, std::move(data), receive_time_ns);
66Ôćĺ        }
67Ôćĺ      };
68Ôćĺ
69Ôćĺ  return inner_manager_.subscribe(topic_name, topic_type, ros2_callback);
70Ôćĺ}
