 43Ôćĺvoid AggregatedMessageSerializer::serialize_message(
 44Ôćĺ    const std::string &topic_name, uint64_t timestamp_ns, const std::byte *data, size_t data_size) {
 45Ôćĺ  message_count_++;
 46Ôćĺ  write_str(serialized_data_, topic_name);
 47Ôćĺ
 48Ôćĺ  // Timestamp (uint64_t) - receive time
 49Ôćĺ  write_le(serialized_data_, timestamp_ns);
 50Ôćĺ
 51Ôćĺ  // Message data length (uint32_t)
 52Ôćĺ  uint32_t msg_size = static_cast<uint32_t>(data_size);
 53Ôćĺ  write_le(serialized_data_, msg_size);
 54Ôćĺ
 55Ôćĺ  // Message data (CDR bytes) using memcpy
 56Ôćĺ  size_t old_size = serialized_data_.size();
 57Ôćĺ  serialized_data_.resize(old_size + msg_size);
 58Ôćĺ  std::memcpy(serialized_data_.data() + old_size, data, msg_size);
 59Ôćĺ}
