 70Ôćĺstd::vector<uint8_t> AggregatedMessageSerializer::finalize() {
 71Ôćĺ  // Build 16-byte header (uncompressed)
 72Ôćĺ  std::vector<uint8_t> header(kBinaryHeaderSize);
 73Ôćĺ
 74Ôćĺ  // Magic (offset 0, 4 bytes, little-endian)
 75Ôćĺ  uint32_t magic = kBinaryFrameMagic;
 76Ôćĺ  std::memcpy(header.data(), &magic, sizeof(magic));
 77Ôćĺ
 78Ôćĺ  // Message count (offset 4, 4 bytes, little-endian)
 79Ôćĺ  uint32_t count = static_cast<uint32_t>(message_count_);
 80Ôćĺ  std::memcpy(header.data() + 4, &count, sizeof(count));
 81Ôćĺ
 82Ôćĺ  // Uncompressed size (offset 8, 4 bytes, little-endian)
 83Ôćĺ  uint32_t uncompressed = static_cast<uint32_t>(serialized_data_.size());
 84Ôćĺ  std::memcpy(header.data() + 8, &uncompressed, sizeof(uncompressed));
 85Ôćĺ
 86Ôćĺ  // Flags (offset 12, 4 bytes, reserved = 0)
 87Ôćĺ  uint32_t flags = 0;
 88Ôćĺ  std::memcpy(header.data() + 12, &flags, sizeof(flags));
 89Ôćĺ
 90Ôćĺ  // Handle empty payload case
 91Ôćĺ  if (serialized_data_.empty()) {
 92Ôćĺ    return header;
 93Ôćĺ  }
 94Ôćĺ
 95Ôćĺ  // Compress the payload
 96Ôćĺ  size_t max_compressed = ZSTD_compressBound(serialized_data_.size());
 97Ôćĺ  std::vector<uint8_t> result(kBinaryHeaderSize + max_compressed);
 98Ôćĺ
 99Ôćĺ  // Copy header to output
100Ôćĺ  std::memcpy(result.data(), header.data(), kBinaryHeaderSize);
101Ôćĺ
102Ôćĺ  // Compress payload after header using persistent context
103Ôćĺ  size_t compressed_size = ZSTD_compressCCtx(
104Ôćĺ      cctx_, result.data() + kBinaryHeaderSize, max_compressed, serialized_data_.data(), serialized_data_.size(),
105Ôćĺ      1  // compression level
106Ôćĺ  );
107Ôćĺ
108Ôćĺ  if (ZSTD_isError(compressed_size)) {
109Ôćĺ    throw std::runtime_error(std::string("ZSTD compression failed: ") + ZSTD_getErrorName(compressed_size));
110Ôćĺ  }
111Ôćĺ
112Ôćĺ  // Resize to actual size: header + compressed payload
113Ôćĺ  result.resize(kBinaryHeaderSize + compressed_size);
114Ôćĺ  return result;
115Ôćĺ}
116Ôćĺ
117Ôćĺvoid AggregatedMessageSerializer::compress_zstd(
118Ôćĺ    const std::vector<uint8_t> &data, std::vector<uint8_t> &compressed_data) {
119Ôćĺ  compressed_data.clear();
120Ôćĺ  if (data.empty()) {
121Ôćĺ    return;
122Ôćĺ  }
123Ôćĺ
124Ôćĺ  // Get maximum compressed size
125Ôćĺ  size_t max_compressed_size = ZSTD_compressBound(data.size());
126Ôćĺ  compressed_data.resize(max_compressed_size);
127Ôćĺ
128Ôćĺ  // Compress (static helper ÔÇö uses one-shot API; hot path uses finalize() with persistent cctx_)
129Ôćĺ  size_t compressed_size = ZSTD_compress(compressed_data.data(), compressed_data.size(), data.data(), data.size(), 1);
130Ôćĺ
131Ôćĺ  // Check for errors
132Ôćĺ  if (ZSTD_isError(compressed_size)) {
133Ôćĺ    throw std::runtime_error(std::string("ZSTD compression failed: ") + ZSTD_getErrorName(compressed_size));
134Ôćĺ  }
135Ôćĺ
136Ôćĺ  // Resize to actual compressed size
137Ôćĺ  compressed_data.resize(compressed_size);
138Ôćĺ}
139Ôćĺ
140Ôćĺvoid AggregatedMessageSerializer::decompress_zstd(
141Ôćĺ    const std::vector<uint8_t> &compressed_data, std::vector<uint8_t> &decompressed) {
142Ôćĺ  decompressed.clear();
143Ôćĺ  if (compressed_data.empty()) {
144Ôćĺ    return;
145Ôćĺ  }
146Ôćĺ
147Ôćĺ  // Get decompressed size
148Ôćĺ  unsigned long long decompressed_size = ZSTD_getFrameContentSize(compressed_data.data(), compressed_data.size());
149Ôćĺ
150Ôćĺ  if (decompressed_size == ZSTD_CONTENTSIZE_ERROR) {
151Ôćĺ    throw std::runtime_error("ZSTD: not compressed by zstd");
152Ôćĺ  }
153Ôćĺ  if (decompressed_size == ZSTD_CONTENTSIZE_UNKNOWN) {
154Ôćĺ    throw std::runtime_error("ZSTD: original size unknown");
155Ôćĺ  }
156Ôćĺ  decompressed.resize(decompressed_size);
157Ôćĺ
158Ôćĺ  // Decompress using persistent context
159Ôćĺ  ZSTD_DCtx *dctx = get_dctx();
160Ôćĺ  size_t result = ZSTD_decompressDCtx(
161Ôćĺ      dctx, decompressed.data(), decompressed.size(), compressed_data.data(), compressed_data.size());
162Ôćĺ
163Ôćĺ  // Check for errors
164Ôćĺ  if (ZSTD_isError(result)) {
165Ôćĺ    throw std::runtime_error(std::string("ZSTD decompression failed: ") + ZSTD_getErrorName(result));
166Ôćĺ  }
167Ôćĺ}
