169Ôćĺtemplate <typename T>
170Ôćĺvoid AggregatedMessageSerializer::write_le(std::vector<uint8_t> &buffer, T value) {
171Ôćĺ  // Write value in little-endian format
172Ôćĺ  for (size_t i = 0; i < sizeof(T); ++i) {
173Ôćĺ    buffer.push_back(static_cast<uint8_t>((value >> (i * 8)) & 0xFF));
174Ôćĺ  }
175Ôćĺ}
176Ôćĺ
177Ôćĺvoid AggregatedMessageSerializer::write_str(std::vector<uint8_t> &buffer, const std::string &str) {
178Ôćĺ  // Write string length
179Ôćĺ  write_le<uint16_t>(buffer, static_cast<uint16_t>(str.size()));
180Ôćĺ  // Write string data
181Ôćĺ  buffer.insert(buffer.end(), str.begin(), str.end());
182Ôćĺ}
183Ôćĺ
184Ôćĺ// Explicit template instantiations
185Ôćĺtemplate void AggregatedMessageSerializer::write_le<uint16_t>(std::vector<uint8_t> &, uint16_t);
186Ôćĺtemplate void AggregatedMessageSerializer::write_le<uint32_t>(std::vector<uint8_t> &, uint32_t);
187Ôćĺtemplate void AggregatedMessageSerializer::write_le<uint64_t>(std::vector<uint8_t> &, uint64_t);
