64Ôćĺvoid MessageBuffer::cleanup_old_messages() {
65Ôćĺ  uint64_t current_time = get_current_time_ns();
66Ôćĺ
67Ôćĺ  for (auto& [topic, buffer] : topic_buffers_) {
68Ôćĺ    while (!buffer.empty()) {
69Ôćĺ      const auto& oldest_msg = buffer.front();
70Ôćĺ      if (current_time - oldest_msg.received_at_ns > max_message_age_ns_) {
71Ôćĺ        buffer.pop_front();
72Ôćĺ      } else {
73Ôćĺ        break;
74Ôćĺ      }
75Ôćĺ    }
76Ôćĺ  }
77Ôćĺ
78Ôćĺ  for (auto it = topic_buffers_.begin(); it != topic_buffers_.end();) {
79Ôćĺ    if (it->second.empty()) {
80Ôćĺ      it = topic_buffers_.erase(it);
81Ôćĺ    } else {
82Ôćĺ      ++it;
83Ôćĺ    }
84Ôćĺ  }
85Ôćĺ}
