 35Ôćĺtl::expected<void, std::string> WebSocketMiddleware::initialize(uint16_t port) {
 36Ôćĺ  std::lock_guard<std::mutex> lock(state_mutex_);
 37Ôćĺ
 38Ôćĺ  if (initialized_) {
 39Ôćĺ    return tl::unexpected<std::string>("WebSocket middleware already initialized");
 40Ôćĺ  }
 41Ôćĺ
 42Ôćĺ  server_ = std::make_shared<ix::WebSocketServer>(port, "0.0.0.0");
 43Ôćĺ
 44Ôćĺ  server_->setOnClientMessageCallback([this](
 45Ôćĺ                                          std::shared_ptr<ix::ConnectionState> connection_state,
 46Ôćĺ                                          ix::WebSocket& web_socket, const ix::WebSocketMessagePtr& msg) {
 47Ôćĺ    {
 48Ôćĺ      std::lock_guard<std::mutex> state_lock(state_mutex_);
 49Ôćĺ      if (!initialized_) {
 50Ôćĺ        return;
 51Ôćĺ      }
 52Ôćĺ    }
 53Ôćĺ
 54Ôćĺ    std::string client_id = connection_state->getId();
 55Ôćĺ
 56Ôćĺ    if (msg->type == ix::WebSocketMessageType::Open) {
 57Ôćĺ      {
 58Ôćĺ        std::lock_guard<std::mutex> clients_lock(clients_mutex_);
 59Ôćĺ        for (const auto& client : server_->getClients()) {
 60Ôćĺ          if (client.get() == &web_socket) {
 61Ôćĺ            clients_[client_id] = client;
 62Ôćĺ            break;
 63Ôćĺ          }
 64Ôćĺ        }
 65Ôćĺ      }
 66Ôćĺ
 67Ôćĺ      ConnectionCallback cb;
 68Ôćĺ      {
 69Ôćĺ        std::lock_guard<std::mutex> state_lock(state_mutex_);
 70Ôćĺ        cb = on_connect_;
 71Ôćĺ      }
 72Ôćĺ      if (cb) {
 73Ôćĺ        cb(client_id);
 74Ôćĺ      }
 75Ôćĺ
 76Ôćĺ    } else if (msg->type == ix::WebSocketMessageType::Close) {
 77Ôćĺ      ConnectionCallback cb;
 78Ôćĺ      {
 79Ôćĺ        std::lock_guard<std::mutex> state_lock(state_mutex_);
 80Ôćĺ        cb = on_disconnect_;
 81Ôćĺ      }
 82Ôćĺ      if (cb) {
 83Ôćĺ        cb(client_id);
 84Ôćĺ      }
 85Ôćĺ
 86Ôćĺ      {
 87Ôćĺ        std::lock_guard<std::mutex> clients_lock(clients_mutex_);
 88Ôćĺ        clients_.erase(client_id);
 89Ôćĺ      }
 90Ôćĺ
 91Ôćĺ    } else if (msg->type == ix::WebSocketMessageType::Message) {
 92Ôćĺ      if (!msg->binary) {
 93Ôćĺ        IncomingRequest req;
 94Ôćĺ        req.client_id = client_id;
 95Ôćĺ        req.data.assign(msg->str.begin(), msg->str.end());
 96Ôćĺ
 97Ôćĺ        {
 98Ôćĺ          std::lock_guard<std::mutex> queue_lock(queue_mutex_);
 99Ôćĺ          if (incoming_queue_.size() >= kMaxIncomingQueueSize) {
100Ôćĺ            spdlog::warn(
101Ôćĺ                "Incoming queue full ({} messages), dropping message from client '{}'", kMaxIncomingQueueSize,
102Ôćĺ                client_id);
103Ôćĺ            return;
104Ôćĺ          }
105Ôćĺ          incoming_queue_.push(std::move(req));
106Ôćĺ        }
107Ôćĺ        queue_cv_.notify_one();
108Ôćĺ      }
109Ôćĺ    }
110Ôćĺ  });
111Ôćĺ
112Ôćĺ  auto listen_result = server_->listen();
113Ôćĺ  if (!listen_result.first) {
114Ôćĺ    server_.reset();
115Ôćĺ    return tl::unexpected<std::string>(
116Ôćĺ        "Failed to listen on port " + std::to_string(port) + ": " + listen_result.second);
117Ôćĺ  }
118Ôćĺ
119Ôćĺ  server_->start();
120Ôćĺ  initialized_ = true;
121Ôćĺ
122Ôćĺ  return {};
123Ôćĺ}
