125Ôćĺvoid WebSocketMiddleware::shutdown() {
126Ôćĺ  std::shared_ptr<ix::WebSocketServer> server_to_stop;
127Ôćĺ
128Ôćĺ  {
129Ôćĺ    std::lock_guard<std::mutex> lock(state_mutex_);
130Ôćĺ
131Ôćĺ    if (!initialized_) {
132Ôćĺ      return;
133Ôćĺ    }
134Ôćĺ
135Ôćĺ    initialized_ = false;
136Ôćĺ    on_connect_ = nullptr;
137Ôćĺ    on_disconnect_ = nullptr;
138Ôćĺ    server_to_stop = std::move(server_);
139Ôćĺ  }
140Ôćĺ
141Ôćĺ  queue_cv_.notify_all();
142Ôćĺ
143Ôćĺ  if (server_to_stop) {
144Ôćĺ    // Replace the message callback with a no-op before stopping. The original
145Ôćĺ    // callback captures `this`, so it must not fire after the WebSocketMiddleware
146Ôćĺ    // instance is destroyed (which can happen if the stop thread is detached on timeout).
147Ôćĺ    server_to_stop->setOnClientMessageCallback(
148Ôćĺ        [](std::shared_ptr<ix::ConnectionState>, ix::WebSocket&, const ix::WebSocketMessagePtr&) {});
149Ôćĺ
150Ôćĺ    // Initiate graceful close on all connected clients before calling stop().
151Ôćĺ    spdlog::debug("[shutdown] Pre-closing {} WebSocket client(s)...", server_to_stop->getClients().size());
152Ôćĺ    for (const auto& client : server_to_stop->getClients()) {
153Ôćĺ      client->close();
154Ôćĺ    }
155Ôćĺ
156Ôćĺ    // Run stop() on a dedicated thread with a timeout.
157Ôćĺ    spdlog::debug("[shutdown] Starting server stop thread...");
158Ôćĺ    auto done = std::make_shared<std::atomic<bool>>(false);
159Ôćĺ    std::thread stop_thread([server_to_stop, done]() {
160Ôćĺ      server_to_stop->stop();
161Ôćĺ      done->store(true);
162Ôćĺ    });
163Ôćĺ
164Ôćĺ    auto start = std::chrono::steady_clock::now();
165Ôćĺ    auto deadline = start + std::chrono::seconds(kShutdownTimeoutSeconds);
166Ôćĺ    while (!done->load() && std::chrono::steady_clock::now() < deadline) {
167Ôćĺ      std::this_thread::sleep_for(std::chrono::milliseconds(50));
168Ôćĺ    }
169Ôćĺ    auto elapsed_ms =
170Ôćĺ        std::chrono::duration_cast<std::chrono::milliseconds>(std::chrono::steady_clock::now() - start).count();
171Ôćĺ
172Ôćĺ    if (done->load()) {
173Ôćĺ      stop_thread.join();
174Ôćĺ      spdlog::debug("[shutdown] Server stop completed (took {}ms)", elapsed_ms);
175Ôćĺ    } else {
176Ôćĺ      // Timeout reached. Detach the thread and let it finish in the background.
177Ôćĺ      // The thread captures server_to_stop by shared_ptr, so the server
178Ôćĺ      // will be destroyed when stop() finishes and the thread exits.
179Ôćĺ      // The message callback was already cleared above, so no use-after-free.
180Ôćĺ      spdlog::warn(
181Ôćĺ          "[shutdown] Server stop timed out after {}s ({}ms elapsed), detaching shutdown thread",
182Ôćĺ          kShutdownTimeoutSeconds, elapsed_ms);
183Ôćĺ      stop_thread.detach();
184Ôćĺ    }
185Ôćĺ  }
186Ôćĺ
187Ôćĺ  {
188Ôćĺ    std::lock_guard<std::mutex> clients_lock(clients_mutex_);
189Ôćĺ    clients_.clear();
190Ôćĺ  }
191Ôćĺ
192Ôćĺ  {
193Ôćĺ    std::lock_guard<std::mutex> queue_lock(queue_mutex_);
194Ôćĺ    std::queue<IncomingRequest> empty;
195Ôćĺ    std::swap(incoming_queue_, empty);
196Ôćĺ  }
197Ôćĺ}
