199Ôćĺbool WebSocketMiddleware::receive_request(std::vector<uint8_t>& data, std::string& client_identity) {
200Ôćĺ  {
201Ôćĺ    std::lock_guard<std::mutex> state_lock(state_mutex_);
202Ôćĺ    if (!initialized_) {
203Ôćĺ      return false;
204Ôćĺ    }
205Ôćĺ  }
206Ôćĺ
207Ôćĺ  std::unique_lock<std::mutex> lock(queue_mutex_);
208Ôćĺ
209Ôćĺ  if (!queue_cv_.wait_for(
210Ôćĺ          lock, std::chrono::milliseconds(kReceiveTimeoutMs), [this]() { return !incoming_queue_.empty(); })) {
211Ôćĺ    return false;
212Ôćĺ  }
213Ôćĺ
214Ôćĺ  auto req = std::move(incoming_queue_.front());
215Ôćĺ  incoming_queue_.pop();
216Ôćĺ
217Ôćĺ  data = std::move(req.data);
218Ôćĺ  client_identity = std::move(req.client_id);
219Ôćĺ  return true;
220Ôćĺ}
