254Ôćĺbool WebSocketMiddleware::publish_data(const std::vector<uint8_t>& data) {
255Ôćĺ  std::vector<std::shared_ptr<ix::WebSocket>> clients_copy;
256Ôćĺ  {
257Ôćĺ    std::lock_guard<std::mutex> lock(clients_mutex_);
258Ôćĺ    if (clients_.empty()) {
259Ôćĺ      return false;
260Ôćĺ    }
261Ôćĺ    clients_copy.reserve(clients_.size());
262Ôćĺ    for (const auto& [client_id, ws] : clients_) {
263Ôćĺ      if (ws) {
264Ôćĺ        clients_copy.push_back(ws);
265Ôćĺ      }
266Ôćĺ    }
267Ôćĺ  }
268Ôćĺ
269Ôćĺ  std::string binary_data(reinterpret_cast<const char*>(data.data()), data.size());
270Ôćĺ  bool any_sent = false;
271Ôćĺ
272Ôćĺ  for (const auto& ws : clients_copy) {
273Ôćĺ    auto send_info = ws->sendBinary(binary_data);
274Ôćĺ    if (send_info.success) {
275Ôćĺ      any_sent = true;
276Ôćĺ    }
277Ôćĺ  }
278Ôćĺ
279Ôćĺ  return any_sent;
280Ôćĺ}
