 27Ôćĺ
 28Ôćĺbool GenericSubscriptionManager::subscribe(
 29Ôćĺ    const std::string& topic_name, const std::string& topic_type, Ros2MessageCallback callback) {
 30Ôćĺ  std::lock_guard<std::mutex> lock(mutex_);
 31Ôćĺ
 32Ôćĺ  auto it = subscriptions_.find(topic_name);
 33Ôćĺ
 34Ôćĺ  if (it != subscriptions_.end()) {
 35Ôćĺ    it->second.reference_count++;
 36Ôćĺ    return true;
 37Ôćĺ  }
 38Ôćĺ
 39Ôćĺ  try {
 40Ôćĺ    auto sub_callback = [topic_name, callback](std::shared_ptr<rclcpp::SerializedMessage> msg) {
 41Ôćĺ      uint64_t receive_time = get_current_time_ns();
 42Ôćĺ      callback(topic_name, msg, receive_time);
 43Ôćĺ    };
 44Ôćĺ
 45Ôćĺ    auto subscription = node_->create_generic_subscription(topic_name, topic_type, rclcpp::QoS(100), sub_callback);
 46Ôćĺ
 47Ôćĺ    subscriptions_[topic_name] = SubscriptionInfo{subscription, 1};
 48Ôćĺ
 49Ôćĺ    return true;
 50Ôćĺ  } catch (const std::exception& e) {
 51Ôćĺ    RCLCPP_ERROR(
 52Ôćĺ        node_->get_logger(), "Failed to create subscription for topic '%s' (type '%s'): %s", topic_name.c_str(),
 53Ôćĺ        topic_type.c_str(), e.what());
 54Ôćĺ    return false;
 55Ôćĺ  }
 56Ôćĺ}
