 58Ôćĺbool GenericSubscriptionManager::unsubscribe(const std::string& topic_name) {
 59Ôćĺ  std::lock_guard<std::mutex> lock(mutex_);
 60Ôćĺ
 61Ôćĺ  auto it = subscriptions_.find(topic_name);
 62Ôćĺ  if (it == subscriptions_.end()) {
 63Ôćĺ    return false;
 64Ôćĺ  }
 65Ôćĺ
 66Ôćĺ  if (it->second.reference_count == 0) {
 67Ôćĺ    return false;
 68Ôćĺ  }
 69Ôćĺ
 70Ôćĺ  it->second.reference_count--;
 71Ôćĺ
 72Ôćĺ  if (it->second.reference_count == 0) {
 73Ôćĺ    subscriptions_.erase(it);
 74Ôćĺ  }
 75Ôćĺ
 76Ôćĺ  return true;
 77Ôćĺ}
