 20Ôćĺ#include <spdlog/spdlog.h>
 21Ôćĺ
 22Ôćĺ#include <chrono>
 23Ôćĺ#include <memory>
 24Ôćĺ#include <rclcpp/rclcpp.hpp>
 25Ôćĺ
 26Ôćĺ#include "pj_bridge/bridge_server.hpp"
 27Ôćĺ#include "pj_bridge/middleware/websocket_middleware.hpp"
 28Ôćĺ#include "pj_bridge_ros2/ros2_subscription_manager.hpp"
 29Ôćĺ#include "pj_bridge_ros2/ros2_topic_source.hpp"
 30Ôćĺ
 31Ôćĺint main(int argc, char** argv) {
 32Ôćĺ  rclcpp::init(argc, argv);
 33Ôćĺ
 34Ôćĺ  auto node = std::make_shared<rclcpp::Node>("pj_bridge");
 35Ôćĺ
 36Ôćĺ  RCLCPP_INFO(node->get_logger(), "Starting pj_bridge (ROS2 backend)...");
 37Ôćĺ
 38Ôćĺ  // Declare and get parameters
 39Ôćĺ  node->declare_parameter<int>("port", 9090);
 40Ôćĺ  node->declare_parameter<double>("publish_rate", 50.0);
 41Ôćĺ  node->declare_parameter<double>("session_timeout", 10.0);
 42Ôćĺ  node->declare_parameter<bool>("strip_large_messages", true);
 43Ôćĺ
 44Ôćĺ  int port = node->get_parameter("port").as_int();
 45Ôćĺ  double publish_rate = node->get_parameter("publish_rate").as_double();
 46Ôćĺ  double session_timeout = node->get_parameter("session_timeout").as_double();
 47Ôćĺ  bool strip_large_messages = node->get_parameter("strip_large_messages").as_bool();
 48Ôćĺ
 49Ôćĺ  RCLCPP_INFO(
 50Ôćĺ      node->get_logger(),
 51Ôćĺ      "Configuration: port=%d, publish_rate=%.1f Hz, session_timeout=%.1f s, strip_large_messages=%s", port,
 52Ôćĺ      publish_rate, session_timeout, strip_large_messages ? "true" : "false");
 53Ôćĺ
 54Ôćĺ  try {
 55Ôćĺ    // Create backend components
 56Ôćĺ    auto topic_source = std::make_shared<pj_bridge::Ros2TopicSource>(node);
 57Ôćĺ    auto sub_manager = std::make_shared<pj_bridge::Ros2SubscriptionManager>(node, strip_large_messages);
 58Ôćĺ    auto middleware = std::make_shared<pj_bridge::WebSocketMiddleware>();
 59Ôćĺ
 60Ôćĺ    // Create bridge server
 61Ôćĺ    pj_bridge::BridgeServer server(topic_source, sub_manager, middleware, port, session_timeout, publish_rate);
 62Ôćĺ
 63Ôćĺ    if (!server.initialize()) {
 64Ôćĺ      RCLCPP_ERROR(node->get_logger(), "Failed to initialize bridge server");
 65Ôćĺ      rclcpp::shutdown();
 66Ôćĺ      return 1;
 67Ôćĺ    }
 68Ôćĺ
 69Ôćĺ    RCLCPP_INFO(node->get_logger(), "Bridge server initialized successfully");
 70Ôćĺ    RCLCPP_INFO(node->get_logger(), "Ready to accept WebSocket connections on port %d", port);
 71Ôćĺ
 72Ôćĺ    // ROS2 timers drive the event loop
 73Ôćĺ    using namespace std::chrono_literals;
 74Ôćĺ
 75Ôćĺ    auto request_timer = node->create_wall_timer(10ms, [&server]() { server.process_requests(); });
 76Ôćĺ
 77Ôćĺ    auto publish_period = std::chrono::duration<double>(1.0 / publish_rate);
 78Ôćĺ    auto publish_timer = node->create_wall_timer(
 79Ôćĺ        std::chrono::duration_cast<std::chrono::nanoseconds>(publish_period),
 80Ôćĺ        [&server]() { server.publish_aggregated_messages(); });
 81Ôćĺ
 82Ôćĺ    auto timeout_timer = node->create_wall_timer(1s, [&server]() { server.check_session_timeouts(); });
 83Ôćĺ
 84Ôćĺ    // Spin until shutdown
 85Ôćĺ    rclcpp::executors::SingleThreadedExecutor executor;
 86Ôćĺ    executor.add_node(node);
 87Ôćĺ
 88Ôćĺ    while (rclcpp::ok()) {
 89Ôćĺ      executor.spin_some(100ms);
 90Ôćĺ    }
 91Ôćĺ
 92Ôćĺ    // Graceful shutdown
 93Ôćĺ    RCLCPP_INFO(node->get_logger(), "Shutting down bridge server...");
 94Ôćĺ
 95Ôćĺ    request_timer->cancel();
 96Ôćĺ    publish_timer->cancel();
 97Ôćĺ    timeout_timer->cancel();
 98Ôćĺ    executor.remove_node(node);
