 70Ôćĺstd::vector<uint8_t> AggregatedMessageSerializer::finalize() {
 71Ôćĺ  // Build 16-byte header (uncompressed)
 72Ôćĺ  std::vector<uint8_t> header(kBinaryHeaderSize);
 73Ôćĺ
 74Ôćĺ  // Magic (offset 0, 4 bytes, little-endian)
 75Ôćĺ  uint32_t magic = kBinaryFrameMagic;
 76Ôćĺ  std::memcpy(header.data(), &magic, sizeof(magic));
